183ecdf1-115f-474d-8ec2-fd5ce3bf2e65	2ab3b987-fc12-4e33-bbfa-5fa1a17dbb13	تقرير حول حالة عنف بين طالبين داخل المؤسسة	حادثة شجار عنيف بين طالبين في ساحة المدرسة	في يوم الأربعاء 15 أكتوبر 2025، حوالي الساعة العاشرة صباحًا، تم تسجيل شجار عنيف بين الطالبين (محمد.ر) و (كريم.س) في ساحة المدرسة أثناء فترة الاستراحة.\nتدخل المشرفون بسرعة لفضّ النزاع ومنع تفاقم الوضع، حيث تبيّن أن أحد الطالبين أصيب بجرح خفيف في الذراع.\nتم نقل الطالب إلى العيادة المدرسية لتلقي الإسعافات الأولية، كما تم إبلاغ الإدارة و استدعاء أولياء الأمور.\nسيتم فتح تحقيق تربوي في الحادثة واتخاذ الإجراءات التأديبية اللازمة وفقًا للنظام الداخلي للمؤسسة.\n\nإمضاء:\n\nمدير المتوسطة\nالأستاذ: أحمد بن يوسف\n\nمع فائق الاحترام,	\N	pending	Destinataire: Directeur Général	http://localhost:3020/api/rapportemp/183ecdf1-115f-474d-8ec2-fd5ce3bf2e65/pdf	2025-10-15 09:10:27.164861	2025-10-15 09:10:28.695502	\N	t	{"summary": "تقرير عن حادثة شجار بين طالبين في ساحة المدرسة، تم تدخل المشرفون لفضّ النزاع، وأصيب أحد الطالبين بجرح خفيف. سيتم فتح تحقيق تربوي في الحادثة.", "urgency": {"level": "متوسط", "score": 9, "source": "hybrid", "levelFr": "très urgent", "reasoning": "L'incident nécessite une attention rapide pour prévenir de futurs conflits", "dictionary_match": true}, "entities": {"dates": ["15 أكتوبر 2025"], "persons": ["محمد.ر", "كريم.س", "أحمد بن يوسف"], "locations": ["ساحة المدرسة", "العيادة المدرسية"], "organizations": ["المؤسسة"]}, "keywords": ["شجار عنيف", "عنف", "شجار", "طالبين", "مدرسة", "مشرفون", "جرح", "تحقيق", "تربوي", "إجراءات"], "metadata": {"model": "llama-3.3-70b-versatile", "provider": "groq", "analyzed_at": "2025-10-15T08:10:28.691Z", "content_length": 519, "hybrid_analysis": true, "dictionary_version": "1.0"}, "severity": {"level": "عالي جدا", "score": 9, "source": "dictionary_priority", "levelFr": "très urgent", "ai_score": 5, "reasoning": "Le conflit a entraîné des blessures et nécessite une enquête", "dictionary_match": true, "dictionary_score": 9}, "sentiment": {"label": "سلبي", "score": 0.4}, "categories": ["حوادث", "مدرسة", "شجار", "تحقيق"], "analysis_method": {"ai_provider": "groq", "fusion_strategy": "dictionary_priority", "dictionary_detected": "veryHigh", "dictionary_keywords_count": 2}}	\N
