ea1081ff-1f32-42c7-b7d6-663ff6ac5a57	17eab49d-0e03-4c68-bfc4-69999f93c5f3	تقرير حول سلوك عدواني لطالب داخل القسم	تصرف عدواني وتهديد لفظي ضد زميل	خالل حصة اللغة العربية ليوم الثالثاء 14 أكتوبر 2025، قام التلميذ سامي.م بتوجيه كلمات نابية وتهديد أحد زمالئه بسبب\nخالف بسيط.\nتم تهدئة الموقف من قبل األستاذ، واسُتدعي التلميذ إلى اإلدارة.\nسيتم اتخاذ إجراءات تربوية وإشراك مستشار التوجيه المدرسي لمتابعة الحالة.\n\nمع فائق الاحترام,	\N	pending	Destinataire: Directeur Général	http://localhost:3020/api/rapportemp/ea1081ff-1f32-42c7-b7d6-663ff6ac5a57/pdf	2025-12-03 13:45:15.77443	2025-12-03 13:45:17.417106	\N	t	{"summary": "تقرير عن سلوك عدواني لطالب داخل القسم، تم توجيه كلمات نابية وتهديد لفظي ضد زميل.", "urgency": {"level": "حرج جدا", "score": 10, "source": "dictionary_override", "levelFr": "urgence maximale", "ai_score": 5, "reasoning": "⚠️ Intervention immédiate requise", "dictionary_match": true}, "entities": {"dates": ["14 أكتوبر 2025"], "persons": ["سامي"], "locations": [], "organizations": []}, "keywords": ["مات", "تهديد", "سلوك عدواني", "تهديد لفظي", "كلمات نابية", "زميل", "قسم", "توجيه", "إدارة", "متابعة"], "metadata": {"model": "llama-3.3-70b-versatile", "provider": "groq", "analyzed_at": "2025-12-03T12:45:17.411Z", "content_length": 277, "hybrid_analysis": true, "dictionary_version": "1.0"}, "severity": {"level": "حرجة للغاية", "score": 10, "source": "dictionary_override", "levelFr": "critique absolu", "ai_score": 5, "reasoning": "🚨 Détection automatique: مات, تهديد", "dictionary_match": true}, "sentiment": {"label": "سلبي", "score": 0.2}, "categories": ["سلوك الطلاب", "مشاكل داخل القسم", "توجيه ومراقبة"], "analysis_method": {"ai_provider": "groq", "fusion_strategy": "dictionary_override", "dictionary_detected": "critical", "dictionary_keywords_count": 2}}	\N
